import { useEffect, useMemo, type ReactNode } from 'react';
import { createOverlayHub, type OverlayConfig } from '@o9ds/core';
import { OverlayContext } from './OverlayContext';

export interface OverlayProviderProps {
  config?: Partial<OverlayConfig>;
  children: ReactNode;
}

export function OverlayProvider({
  config,
  children,
}: OverlayProviderProps): JSX.Element {
  // Each provider owns an isolated hub instance.
  // Apply initial config synchronously inside useMemo so it is available
  // before the first child render (not deferred to a useEffect).
  const hub = useMemo(() => {
    const h = createOverlayHub();
    if (config) h.configure(config);
    return h;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Re-apply when config object changes after mount.
  useEffect(() => {
    if (config) hub.configure(config);
  }, [hub, config]);

  return (
    <OverlayContext.Provider value={hub}>{children}</OverlayContext.Provider>
  );
}
